  ('locality-7c9828ae-moex-00175', 'locality-7c9828ae', 'locality-7c9828ae-moex-112-d1a761c9', 'sub-locality-7c9828ae-03', NULL, 'single_choice', '警察執勤中見爛醉之甲騎機車，未施以對人之即時強制管束任其離去，致甲隨後肇事身亡，下列敘述何者 正確？', '["警察機關於此情形屬於怠於執行職務，構成國家賠償責任", "甲之死亡屬於國家賠償法中之自願從事冒險或危險性活動，不構成國家賠償責任", "警察機關並未對甲有違法不當之攔檢，自不負國家賠償責任", "即時強制係為公共利益而設，無國家賠償法適用之餘地"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:07+00:00", "source_pdf_sha1": "63c794400f58", "answer_pdf_sha1": "ae862658c350", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "407", "s": "0711", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "社會工作"}'::jsonb, NULL),
